import{_ as e,o as a,c as i,a4 as n}from"./chunks/framework.CtnSHCpE.js";const g=JSON.parse('{"title":"Collecting Usage Statistics with the zopen community Package Manager","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/Analytics.md","filePath":"Guides/Analytics.md","lastUpdated":1734124443000}'),o={name:"Guides/Analytics.md"};function s(r,t,l,c,d,u){return a(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="collecting-usage-statistics-with-the-zopen-community-package-manager" tabindex="-1">Collecting Usage Statistics with the zopen community Package Manager <a class="header-anchor" href="#collecting-usage-statistics-with-the-zopen-community-package-manager" aria-label="Permalink to &quot;Collecting Usage Statistics with the zopen community Package Manager&quot;">​</a></h1><p>Usage statistics collection in zopen community Package Manager was introduced to gather anonymized usage data. The collected usage data plays an important role in improving functionality, identifying popular packages, and optimizing zopen community user experience. The usage statistics are viewable at this url: <a href="https://usage.zopen.community/" target="_blank" rel="noreferrer">https://usage.zopen.community/</a></p><h2 id="how-to-opt-in" tabindex="-1">How to Opt-In <a class="header-anchor" href="#how-to-opt-in" aria-label="Permalink to &quot;How to Opt-In&quot;">​</a></h2><ul><li>During the initialization process using the zopen init command, users will be prompted to opt-in or opt-out of statistics collection.</li><li>Users can also pass in the following options to `zopen init: <ul><li><code>--enable-stats</code>: Enables the collection of usage statistics.</li><li><code>--noenable-stats</code>: Disables the collection of usage statistics.</li></ul></li></ul><p>Note: IBM hostnames are automatically opted in.</p><h2 id="how-to-opt-out-after-opting-in" tabindex="-1">How to Opt-Out After Opting In <a class="header-anchor" href="#how-to-opt-out-after-opting-in" aria-label="Permalink to &quot;How to Opt-Out After Opting In&quot;">​</a></h2><ul><li>If you initially opted in but now wish to opt out, you can set the <code>is_collecting_stats</code> field to false in the JSON file located at: <code>$ZOPEN_ROOTFS/etc/zopen/config.json</code>.</li></ul><h2 id="data-captured" tabindex="-1">Data Captured <a class="header-anchor" href="#data-captured" aria-label="Permalink to &quot;Data Captured&quot;">​</a></h2><ol><li><p><strong>Package Installations:</strong></p><ul><li><strong>Package Name:</strong> Identifies the installed package.</li><li><strong>Version:</strong> Captures the version of the installed package.</li><li><strong>Timestamp:</strong> Records the installation date and time.</li><li><strong>Upgrade Status:</strong> Indicates whether the installation is an upgrade.</li><li><strong>Runtime Dependency:</strong> Indicates whether the installation is installed as part of a runtime dependency</li><li><strong>Build Install:</strong> Indicates whether the installation is installed as part of a build install</li></ul></li><li><p><strong>Package Removals:</strong></p><ul><li><strong>Package Name:</strong> Specifies the removed package.</li><li><strong>Version:</strong> Captures the version of the removed package.</li><li><strong>Timestamp:</strong> Records the removal date and time.</li></ul></li><li><p><strong>System Profile:</strong></p><ul><li><strong>UUID:</strong> Provides a unique identifier for the user&#39;s system profile. This is generated by using the current date and a random number and does not rely on any sensitive information.</li><li><strong>IBM Host Status:</strong> Indicates whether the host is an IBM server.</li><li><strong>Bot Status:</strong> Identifies whether the script is executed in a Jenkins, CI/CD environment.</li></ul></li></ol><h2 id="ensuring-anonymity-and-privacy" tabindex="-1">Ensuring Anonymity and Privacy <a class="header-anchor" href="#ensuring-anonymity-and-privacy" aria-label="Permalink to &quot;Ensuring Anonymity and Privacy&quot;">​</a></h2><p>All collected data is anonymized and no personal data is recorded.</p><p>We do not capture any sensitive information such as your ip address, hostname, or file system details.</p><p>If you have opted out, usage statistics will not be collected.</p><h2 id="usage-statistics" tabindex="-1">Usage Statistics <a class="header-anchor" href="#usage-statistics" aria-label="Permalink to &quot;Usage Statistics&quot;">​</a></h2><p>Browse <a href="https://usage.zopen.community" target="_blank" rel="noreferrer">https://usage.zopen.community</a><a href="https://usage.zopen.community" title=":include :type=iframe name=&quot;iframe1&quot; width=100% height=100% frameborder=&quot;0&quot; scrolling=&quot;yes&quot; onload=&quot;styleandresizeIframe(this)&quot;" target="_blank" rel="noreferrer"></a></p>',15)])])}const h=e(o,[["render",s]]);export{g as __pageData,h as default};
